package com.valcrono.testapp.a
import android.app.*; import android.os.*; import android.database.sqlite.SQLiteDatabase; import androidx.activity.ComponentActivity; import androidx.activity.compose.setContent; import androidx.compose.foundation.layout.*; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.Modifier; import androidx.compose.ui.unit.dp
class MainActivity:ComponentActivity(){ override fun onCreate(b:Bundle?){ super.onCreate(b); setContent{ var c by remember{mutableStateOf(0)}; MaterialTheme{ Column(Modifier.padding(16.dp)){ Text("TestApp A contador=$c"); Text("filesDir=$filesDir\ncacheDir=$cacheDir\ndb=${getDatabasePath("a.db")}"); Button({c++}){Text("Incrementar")}; Button({java.io.File(filesDir,"a-file.txt").writeText("counter=$c")}){Text("Guardar archivo")}; Button({getSharedPreferences("prefs",0).edit().putInt("counter",c).apply()}){Text("Guardar SharedPreferences")}; Button({val db=SQLiteDatabase.openOrCreateDatabase(getDatabasePath("a.db"),null); db.execSQL("CREATE TABLE IF NOT EXISTS events(id INTEGER PRIMARY KEY, msg TEXT)"); db.execSQL("INSERT INTO events(msg) VALUES(?)", arrayOf("counter=$c")); db.close()}){Text("Guardar SQLite")}; Button({java.io.File(filesDir,"virtual-message-to-b.txt").writeText("Hola desde A contador=$c")}){Text("Enviar mensaje virtual a B")}; } } } } }
